const { SQSClient, SendMessageCommand, ReceiveMessageCommand, DeleteMessageCommand } = require('@aws-sdk/client-sqs');
const { SecretsManagerClient, GetSecretValueCommand } = require('@aws-sdk/client-secrets-manager');
const crypto = require('crypto');

const sqsClient = new SQSClient({ region: 'us-east-1' });
const secretsClient = new SecretsManagerClient({ region: 'us-east-1' });

let HMAC_SECRET;

// Initialize HMAC secret from Secrets Manager
async function initializeSecret() {
  try {
    const response = await secretsClient.send(
      new GetSecretValueCommand({ SecretId: 'sqs-message-hmac-key' })
    );
    HMAC_SECRET = response.SecretString;
    console.log('HMAC secret loaded from Secrets Manager');
  } catch (error) {
    console.error('Failed to load HMAC secret:', error);
    process.exit(1);
  }
}

// Generate HMAC-SHA256 signature for message
function generateSignature(messageBody) {
  const hmac = crypto.createHmac('sha256', HMAC_SECRET);
  hmac.update(JSON.stringify(messageBody));
  return hmac.digest('hex');
}

// Verify message signature (constant-time comparison)
function verifySignature(messageBody, signature) {
  const expectedSignature = generateSignature(messageBody);
  return crypto.timingSafeEqual(
    Buffer.from(signature, 'hex'),
    Buffer.from(expectedSignature, 'hex')
  );
}

// Producer: Send signed message to SQS
async function sendSignedMessage(queueUrl, orderData) {
  const timestamp = Date.now();
  const messageBody = { ...orderData, timestamp };
  const signature = generateSignature(messageBody);

  const params = {
    QueueUrl: queueUrl,
    MessageBody: JSON.stringify(messageBody),
    MessageAttributes: {
      Signature: {
        DataType: 'String',
        StringValue: signature
      },
      Version: {
        DataType: 'String',
        StringValue: '1.0'
      }
    },
    // For FIFO queues: prevent replay attacks
    MessageDeduplicationId: crypto.createHash('sha256').update(JSON.stringify(messageBody)).digest('hex'),
    MessageGroupId: orderData.customerId
  };

  try {
    const result = await sqsClient.send(new SendMessageCommand(params));
    console.log('Signed message sent:', result.MessageId);
    return result;
  } catch (error) {
    console.error('Failed to send message:', error);
    throw error;
  }
}

// Consumer: Receive and verify signed message
async function receiveAndVerifyMessage(queueUrl) {
  const params = {
    QueueUrl: queueUrl,
    MaxNumberOfMessages: 1,
    WaitTimeSeconds: 20,
    MessageAttributeNames: ['All']
  };

  try {
    const result = await sqsClient.send(new ReceiveMessageCommand(params));

    if (!result.Messages || result.Messages.length === 0) {
      return null;
    }

    const message = result.Messages[0];
    const messageBody = JSON.parse(message.Body);
    const signature = message.MessageAttributes?.Signature?.StringValue;

