// Cache for SNS signing certificates (validate once per cert URL)
const certificateCache = new Map();

// Fetch and cache SNS signing certificate
async function getSigningCertificate(certUrl) {
  // Validate certificate URL is from AWS
  const allowedHosts = [
    'sns.us-east-1.amazonaws.com',
    'sns.us-west-2.amazonaws.com',
    'sns.eu-west-1.amazonaws.com'
    // Add other regions as needed
  ];

  const url = new URL(certUrl);
  if (!allowedHosts.includes(url.hostname)) {
    throw new Error(`Invalid certificate URL host: ${url.hostname}`);
  }

  if (url.protocol !== 'https:') {
    throw new Error('Certificate URL must use HTTPS');
  }

  // Check cache first
  if (certificateCache.has(certUrl)) {
    return certificateCache.get(certUrl);
  }

  // Fetch certificate
  return new Promise((resolve, reject) => {
    https.get(certUrl, (res) => {
      let data = '';
      res.on('data', (chunk) => { data += chunk; });
      res.on('end', () => {
        certificateCache.set(certUrl, data);
        resolve(data);
      });
    }).on('error', reject);
  });
}

// Verify SNS message signature
async function verifySnsSignature(message) {
  const { Type, SignatureVersion, Signature, SigningCertURL } = message;

  // Only support SignatureVersion 1
  if (SignatureVersion !== '1') {
    throw new Error(`Unsupported signature version: ${SignatureVersion}`);
  }

  // Get signing certificate
  const certificate = await getSigningCertificate(SigningCertURL);

  // Build canonical string to verify based on message type
  let canonicalString;
  if (Type === 'Notification') {
    canonicalString = [
      'Message', message.Message,
      'MessageId', message.MessageId,
      'Subject', message.Subject || '',
      'Timestamp', message.Timestamp,
      'TopicArn', message.TopicArn,
      'Type', message.Type
    ].join('\n') + '\n';
  } else if (Type === 'SubscriptionConfirmation' || Type === 'UnsubscribeConfirmation') {
    canonicalString = [
      'Message', message.Message,
      'MessageId', message.MessageId,
      'SubscribeURL', message.SubscribeURL,
      'Timestamp', message.Timestamp,
      'Token', message.Token,
      'TopicArn', message.TopicArn,
      'Type', message.Type
    ].join('\n') + '\n';
  } else {
    throw new Error(`Unknown message type: ${Type}`);
  }

  // Verify signature using RSA-SHA1 or RSA-SHA256
  const verifier = crypto.createVerify('RSA-SHA1');
  verifier.update(canonicalString, 'utf8');

  const isValid = verifier.verify(certificate, Signature, 'base64');
  return isValid;
}

