      console.log('📭 Unsubscribe confirmation received');
      // Log for audit
      await logSecurityEvent('SNS_UNSUBSCRIBE', {
        topicArn: message.TopicArn,
        endpoint: message.Endpoint
      });
      return res.status(200).json({ message: 'Unsubscribe confirmed' });
    }

    // Process notification
    if (message.Type === 'Notification') {
      const notification = JSON.parse(message.Message);
      console.log('📬 Processing notification:', notification);

      // Verify notification freshness (prevent replay)
      const messageAge = Date.now() - new Date(message.Timestamp).getTime();
      if (messageAge > 300000) { // 5 minutes
        console.error('⚠️ Notification too old - potential replay attack');
        return res.status(400).json({ error: 'Message expired' });
      }

      // Process notification business logic
      await processNotification(notification);

      return res.status(200).json({ message: 'Notification processed' });
    }

    res.status(400).json({ error: 'Unknown message type' });
  } catch (error) {
    console.error('SNS endpoint error:', error);
    res.status(500).json({ error: 'Internal server error' });
  }
});

