// Node.js: Message attribute validation and deduplication
const { SQSClient, SendMessageCommand } = require('@aws-sdk/client-sqs');
const crypto = require('crypto');

const sqsClient = new SQSClient({ region: 'us-east-1' });

// Schema for message validation
const ORDER_MESSAGE_SCHEMA = {
  orderId: { type: 'string', pattern: /^ORD-[0-9]{5}$/ },
  customerId: { type: 'string', pattern: /^CUST-[0-9]{5}$/ },
  totalAmount: { type: 'number', min: 0.01, max: 100000 },
  items: { type: 'array', minLength: 1, maxLength: 100 },
  timestamp: { type: 'number' }
};

// Validate message against schema
function validateMessage(message) {
  for (const [field, rules] of Object.entries(ORDER_MESSAGE_SCHEMA)) {
    if (!message.hasOwnProperty(field)) {
      throw new Error(`Missing required field: ${field}`);
    }

    const value = message[field];

    if (rules.type === 'string' && typeof value !== 'string') {
      throw new Error(`Invalid type for ${field}: expected string`);
    }

    if (rules.type === 'number' && typeof value !== 'number') {
      throw new Error(`Invalid type for ${field}: expected number`);
    }

    if (rules.pattern && !rules.pattern.test(value)) {
      throw new Error(`Invalid format for ${field}`);
    }

    if (rules.min !== undefined && value < rules.min) {
      throw new Error(`${field} below minimum: ${rules.min}`);
    }

    if (rules.max !== undefined && value > rules.max) {
      throw new Error(`${field} exceeds maximum: ${rules.max}`);
    }

    if (rules.type === 'array') {
      if (!Array.isArray(value)) {
        throw new Error(`Invalid type for ${field}: expected array`);
      }
      if (rules.minLength && value.length < rules.minLength) {
        throw new Error(`${field} array too short`);
      }
      if (rules.maxLength && value.length > rules.maxLength) {
        throw new Error(`${field} array too long`);
      }
    }
  }

  return true;
}

// Send message with validation and deduplication
async function sendValidatedMessage(queueUrl, orderData) {
  // Validate message structure
  try {
    validateMessage(orderData);
  } catch (error) {
    console.error('❌ Message validation failed:', error.message);
    throw error;
  }

  // Generate content-based deduplication ID
  const deduplicationId = crypto
    .createHash('sha256')
    .update(JSON.stringify({
      orderId: orderData.orderId,
      customerId: orderData.customerId,
      timestamp: Math.floor(orderData.timestamp / 1000) // 1-second precision
    }))
    .digest('hex');

  const params = {
    QueueUrl: queueUrl,
    MessageBody: JSON.stringify(orderData),
    MessageGroupId: orderData.customerId, // Ensures ordering per customer
    MessageDeduplicationId: deduplicationId,
    MessageAttributes: {
      ContentType: {
        DataType: 'String',
        StringValue: 'application/json'
      },
      SchemaVersion: {
        DataType: 'String',
        StringValue: '1.0'
      },
      Priority: {
        DataType: 'Number',
        StringValue: orderData.totalAmount > 1000 ? '1' : '2'
      }
    }
  };

  try {
    const result = await sqsClient.send(new SendMessageCommand(params));
    console.log('✅ Validated message sent:', result.MessageId);
    return result;
  } catch (error) {
    if (error.name === 'InvalidMessageContents') {
      console.error('❌ Message rejected by SQS - potential injection attempt');
      await logSecurityEvent('SQS_MESSAGE_INJECTION_ATTEMPT', {
        queueUrl,
        error: error.message
      });
    }
    throw error;
  }
}

